#include <numeric>
#include <vector>

bool solve(long long n) {
    // Calculate the sum of digits
    long long digit_sum = 0;
    long long temp = n;
    while (temp > 0) {
        digit_sum += temp % 10;
        temp /= 10;
    }

    // Calculate the product of digits
    long long digit_product = 1;
    temp = n;
    while (temp > 0) {
        int digit = temp % 10;
        digit_product *= digit;
        temp /= 10;
    }

    // Check if n is divisible by the sum of the digits and the product of the digits
    return (digit_sum + digit_product) != 0 && n % (digit_sum + digit_product) == 0;
}
